('additional-maths:7-1-exponential-functions:fib:2ed601d8', 'additional-maths', 'additional-maths:7-1-exponential-functions', '7.1 Exponential Functions', 'fib', 'fib', 2, '{"question": "The horizontal asymptote of \\( y = k a^x \\) is the line where \\( y \\) equals ___B1___, which the curve approaches but never ___B2___.", "blankOptions": {"B1": ["above", "1.04", "0", "a"], "B2": ["touches", "base", "growth", "below"]}}'::jsonb, '{"blanks": {"B1": "0", "B2": "touches"}}'::jsonb),
('additional-maths:7-1-exponential-functions:fib:48b2cdaf', 'additional-maths', 'additional-maths:7-1-exponential-functions', '7.1 Exponential Functions', 'fib', 'fib', 2, '{"question": "Since \\( a^x \\) is always positive and \\( k > 0 \\), the value of \\( y \\) is always ___B1___, so the curve stays ___B2___ the \\( x \\)-axis.", "blankOptions": {"B1": ["0.96", "positive", "below", "base"], "B2": ["above", "y-intercept", "linear", "rate"]}}'::jsonb, '{"blanks": {"B1": "positive", "B2": "above"}}'::jsonb),
('additional-maths:7-1-exponential-functions:fib:7b17d2a9', 'additional-maths', 'additional-maths:7-1-exponential-functions', '7.1 Exponential Functions', 'fib', 'fib', 1, '{"question": "The graph of \\( y = k a^x \\) always crosses the \\( y \\)-axis at the point whose \\( y \\)-coordinate equals ___B1___.", "blankOptions": {"B1": ["below", "k", "a", "base"]}}'::jsonb, '{"blanks": {"B1": "k"}}'::jsonb),
('additional-maths:7-1-exponential-functions:fib:bd44d385', 'additional-maths', 'additional-maths:7-1-exponential-functions', '7.1 Exponential Functions', 'fib', 'fib', 1, '{"question": "A savings account of £500 growing at 4% each year is modelled by \\( y = 500 \\times a^x \\), where \\( a \\) equals ___B1___.", "blankOptions": {"B1": ["a", "rate", "linear", "1.04"]}}'::jsonb, '{"blanks": {"B1": "1.04"}}'::jsonb),
('additional-maths:7-1-exponential-functions:fib:b31d7a87', 'additional-maths', 'additional-maths:7-1-exponential-functions', '7.1 Exponential Functions', 'fib', 'fib', 1, '{"question": "If \\( a = 1 \\) then \\( a^x = 1 \\) for every \\( x \\), so the graph is a ___B1___ horizontal line.", "blankOptions": {"B1": ["k", "negative", "constant", "growth"]}}'::jsonb, '{"blanks": {"B1": "constant"}}'::jsonb),
