('additional-maths:7-1-exponential-functions:match:57ab710f', 'additional-maths', 'additional-maths:7-1-exponential-functions', '7.1 Exponential Functions', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Base \\( a > 1 \\)”?", "options": ["Decay; \\( y \\)-intercept \\( (0,\\ 100) \\)", "Exponential growth", "Vertical scale and starting value", "Base \\( a = 0.8 \\)"]}'::jsonb, '{"answer": 1, "explain": "“Base \\( a > 1 \\)” means: Exponential growth"}'::jsonb)
